                log.debug("Get the order ref num -----> for sts001");
            }
            extCustomerId = getExtCustomerId(carrierData);
        }

        item.setExtCustomerId(extCustomerId);
        // Further processing or transformation

        return new BeamDataDTO();
    }

    public String getExtCustomerId(CarrierData carrierData) {
        String extCustomerId = null;
        if (StringUtils.isNotEmpty(carrierData.getOrderRef()) && StringUtils.isNotEmpty(carrierData.getReturnOrderNo())) {
            log.debug("Get the extCustNum against the order ref -----> {}", carrierData.getOrderRef());

